node - <<'NODE' > /tmp/awesome_codex_skill_inventory.tsv
const fs = require('fs');
const cp = require('child_process');
const paths = cp.execSync("find awesome-codex-skills/en -name SKILL.md | sort", {encoding:'utf8'}).trim().split('\n').filter(Boolean);
function parseFm(txt){
  if(!txt.startsWith('---')) return {};
  const end = txt.indexOf('\n---', 3);
  if(end < 0) return {};
  const lines = txt.slice(4,end).split('\n');
  const out = {};
  let current = null;
  for(const line of lines){
    const m = line.match(/^([A-Za-z0-9_-]+):\s*(.*)$/);
    if(m){ current = m[1]; out[current] = m[2].trim().replace(/^['"]|['"]$/g,''); }
    else if(current && /^\s+/.test(line)){ out[current] += ' ' + line.trim(); }
  }
  return out;
}
function shellQuote(s){ return `'${s.replace(/'/g,"'\\''")}'`; }
console.log(['slug','name','allowed','file_count','line_count','has_claude','has_composio','has_mcp','description'].join('\t'));
for (const p of paths){
  const txt = fs.readFileSync(p,'utf8');
  const fm = parseFm(txt);
  const slug = p.replace(/^awesome-codex-skills\/en\//,'').replace(/\/SKILL.md$/,'');
  const dir = p.replace(/\/SKILL.md$/,'');
  const fileCount = cp.execSync(`find ${shellQuote(dir)} -type f | wc -l`, {encoding:'utf8'}).trim();
  const lineCount = txt.split('\n').length;
  const allTxt = cp.execSync(`find ${shellQuote(dir)} -type f -maxdepth 5 -print0 | xargs -0 cat 2>/dev/null`, {encoding:'utf8', maxBuffer: 50_000_000});
  const desc = (fm.description||'').replace(/\s+/g,' ').replace(/\t/g,' ').trim();
  const row = [slug, fm.name||'', fm['allowed-tools']||'', fileCount, lineCount, /Claude/i.test(allTxt)?'yes':'no', /Composio|Rube/i.test(allTxt)?'yes':'no', /MCP|mcp/i.test(allTxt)?'yes':'no', desc];
  console.log(row.map(v => String(v).replace(/\t/g,' ').replace(/\n/g,' ')).join('\t'));
}
