const fs = require('fs');
const invLines = fs.readFileSync('/tmp/awesome_codex_skill_inventory.tsv','utf8').trim().split('
');
const headers = invLines[0].split('	');
const inv = new Map(invLines.slice(1).map(l => {
  const parts = l.split('	');
  const o = Object.fromEntries(headers.map((h,i)=>[h,parts[i]||'']));
  return [o.slug,o];
}));
const decLines = fs.readFileSync('/tmp/awesome_codex_skill_decisions.tsv','utf8').trim().split('
').slice(1);
const rows = decLines.map(l => {
  const [slug, verdict, reason] = l.split('	');
  return {...inv.get(slug), slug, verdict, reason};
});
const order = ['推荐放','条件放','不放'];
const counts = Object.fromEntries(order.map(v => [v, rows.filter(r=>r.verdict===v).length]));
function esc(s){ return (s||'').replace(/\|/g,'\|').replace(/
/g,' '); }
function table(filter){
  const out = ['| Skill | 判定理由 | 备注 |','|---|---|---|'];
  for(const r of rows.filter(filter)){
    const notes = [];
    if(r.has_composio === 'yes') notes.push('Composio/Rube 依赖');
    if(r.has_mcp === 'yes') notes.push('MCP/外部服务');
    if(Number(r.file_count) >= 20) notes.push(`${r.file_count} files`);
    if(r.has_claude === 'yes') notes.push('仍含 Claude 文案，安装前需复核');
    out.push(`| \`${esc(r.slug)}\` | ${esc(r.reason)} | ${esc(notes.join('; ') || '-')} |`);
  }
  return out.join('
');
}
const recommended = rows.filter(r=>r.verdict==='推荐放').map(r=>`\`${r.slug.split('/').pop()}\``).join(', ');
